VALUES ('914599e4-a503-4a61-89fa-c5575d1c90ff', 'sl', 70, 1, NULL, 'Patrística', 'Apressura-te, ó Deus. Atanásio de Alexandria comenta sobre a urgência da salvação.', 'Atanásio de Alexandria', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('5d49848f-3302-4bba-b0e0-9f99b2a24b2c', 'sl', 71, 1, NULL, 'Patrística', 'Em ti, Senhor, me refugio. Basílio Magno comenta sobre a proteção de Deus.', 'Basílio Magno', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('fbe03cd7-4b6a-4d06-a26b-317a3ca50892', 'sl', 73, 1, NULL, 'Patrística', 'Verdadeiramente Deus é bom. Gregório de Nazianzo comenta sobre a bondade de Deus.', 'Gregório de Nazianzo', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
