VALUES ('d1f8ed91-d902-4668-b149-9b8130023af0', 'sl', 75, 1, NULL, 'Patrística', 'Damos-te graças, ó Deus. João Crisóstomo comenta sobre a ação de graças.', 'João Crisóstomo', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('dff7f02a-b4b2-477b-a33c-7bdb148c0a38', 'sl', 76, 1, NULL, 'Patrística', 'Deus é conhecido em Judá. Jerônimo comenta sobre a revelação de Deus.', 'Jerônimo', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('68f7c1a2-0ee8-40cd-8941-008fbfb67954', 'sl', 77, 1, NULL, 'Patrística', 'Clamo a Deus com a minha voz. Clemente de Roma comenta sobre a oração fervorosa.', 'Clemente de Roma', 'commentary', '#6B21A8', NOW());

