INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('4c2aad10-1bfd-4d83-9510-b408750d2fc9', 'sl', 79, 1, NULL, 'Patrística', 'Ó Deus, as nações invadiram. Policarpo comenta sobre a vindição de Deus.', 'Policarpo de Esmirna', 'commentary', '#6B21A8', NOW());

