INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('6d4ec97d-21db-4d16-8d4a-dad5770f8edb', 'sl', 83, 1, NULL, 'Patrística', 'Ó Deus, não fiques em silêncio. Orígenes comenta sobre a intervenção de Deus.', 'Orígenes', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('0fac5fd5-1d1c-48d2-9d34-3d3b2901e6f2', 'sl', 84, 1, NULL, 'Patrística', 'Quão amáveis são teus tabernáculos. Atanásio de Alexandria comenta sobre a beleza da casa de Deus.', 'Atanásio de Alexandria', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('f6a0c852-9524-4602-bfef-8a6407c92b70', 'sl', 85, 1, NULL, 'Patrística', 'Senhor, foste favorável à tua terra. Basílio Magno comenta sobre a restauração de Deus.', 'Basílio Magno', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('6ed21a11-b13b-4f9d-bc44-546188bfeb82', 'sl', 86, 1, NULL, 'Patrística', 'Inclina, Senhor, o teu ouvido. Gregório de Nazianzo comenta sobre a oração fervorosa.', 'Gregório de Nazianzo', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('56874b56-0b01-4afd-893d-3a2a97c45b53', 'sl', 87, 1, NULL, 'Patrística', 'Seus fundamentos estão nos montes santos. Gregório de Nissa comenta sobre a solidez de Deus.', 'Gregório de Nissa', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('578e3775-05c2-4d02-bf2d-5e78f1cc0de7', 'sl', 88, 1, NULL, 'Patrística', 'Senhor, Deus da minha salvação. João Crisóstomo comenta sobre a salvação de Deus.', 'João Crisóstomo', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('52fc5601-f0dd-4bb0-9f3a-3719dd7d4a14', 'sl', 89, 1, NULL, 'Patrística', 'Cantarei eternamente as misericórdias do Senhor. Jerônimo comenta sobre a fidelidade de Deus.', 'Jerônimo', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('7320d0ca-16f3-4566-9ee4-8cacda1fe071', 'sl', 90, 1, NULL, 'Patrística', 'Senhor, tu foste nosso refúgio. Clemente de Roma comenta sobre a proteção de Deus.', 'Clemente de Roma', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('b691d36e-7c31-415e-a5b1-ee2346400625', 'sl', 91, 1, NULL, 'Patrística', 'Aquele que habita no esconderijo. Inácio de Antioquia comenta sobre a proteção de Deus.', 'Inácio de Antioquia', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('badc19f4-1d32-4368-b9fe-9477a3881c5c', 'sl', 92, 1, NULL, 'Patrística', 'Bom é louvar o Senhor. Policarpo comenta sobre o louvor a Deus.', 'Policarpo de Esmirna', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('57078718-4498-490d-97c1-3ea5d6b0ee2d', 'sl', 93, 1, NULL, 'Patrística', 'O Senhor reina. Justino Mártir comenta sobre o reino de Deus.', 'Justino Mártir', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('4949edd9-c3ee-49d2-8049-ecc4138136f4', 'sl', 94, 1, NULL, 'Patrística', 'Deus da vingança, Senhor. Irineu de Lyon comenta sobre a justiça de Deus.', 'Irineu de Lyon', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('cc6fa226-5c63-4deb-8ae8-adda9e2c87a2', 'sl', 95, 1, NULL, 'Patrística', 'Vinde, cantemos ao Senhor. Tertuliano comenta sobre a adoração de Deus.', 'Tertuliano', 'commentary', '#6B21A8', NOW());

