VALUES ('6ff323e6-5e2f-4732-9043-5200985e223f', 'sl', 96, 1, NULL, 'Patrística', 'Cantai ao Senhor uma nova canção. Orígenes comenta sobre a alegria em Deus.', 'Orígenes', 'commentary', '#6B21A8', NOW());

