VALUES ('d6a05bff-b4b4-4b80-bd75-42f49a65c9ab', 'sl', 97, 1, NULL, 'Patrística', 'O Senhor reina. Atanásio de Alexandria comenta sobre o reino de Deus.', 'Atanásio de Alexandria', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('8b182ecb-947c-4fb3-87e0-b0a7d71e77e6', 'sl', 98, 1, NULL, 'Patrística', 'Cantai ao Senhor uma nova canção. Basílio Magno comenta sobre a alegria em Deus.', 'Basílio Magno', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('cda98381-5c04-4768-983b-d75b8106c7c6', 'sl', 99, 1, NULL, 'Patrística', 'O Senhor reina. Gregório de Nazianzo comenta sobre o reino de Deus.', 'Gregório de Nazianzo', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('cf998028-8430-4baf-8e72-d1e0b217fd80', 'sl', 100, 1, NULL, 'Patrística', 'Fazei barulho a Deus. Gregório de Nissa comenta sobre a alegria em Deus.', 'Gregório de Nissa', 'commentary', '#6B21A8', NOW());

