VALUES ('dd05b451-63c3-4448-85c8-364687b19a19', 'is', 2, 1, NULL, 'Patrística', 'Nos últimos dias. João Crisóstomo comenta que Isaías profetiza sobre a exaltação do templo.', 'João Crisóstomo', 'commentary', '#6B21A8', NOW());

