VALUES ('cdd6d890-549a-4b77-a6ff-7410c10f5800', 'is', 9, 1, NULL, 'Patrística', 'Para nós um filho nascerá. Clemente de Roma vê nesta profecia uma predição de Cristo.', 'Clemente de Roma', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('2a2247f3-c772-402c-8871-5a08948f0944', 'is', 11, 1, NULL, 'Patrística', 'Sairá um rebento da raiz de Jessé. Inácio de Antioquia vê nesta profecia uma predição de Cristo.', 'Inácio de Antioquia', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
