INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('19cbc3c6-0530-4d2c-bb78-dc14f136bbbe', 'is', 49, 1, NULL, 'Patrística', 'O Senhor me chamou desde o ventre. Tertuliano comenta sobre o chamado de Deus.', 'Tertuliano', 'commentary', '#6B21A8', NOW());

