VALUES ('b2f9d04f-92d1-4911-8772-d8e5b207f23c', 'is', 52, 1, NULL, 'Patrística', 'Eis que meu servo agirá com prudência. Orígenes comenta sobre a sabedoria de Cristo.', 'Orígenes', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('a5164a7f-0c94-4cec-96e5-894bece79f48', 'is', 61, 1, NULL, 'Patrística', 'O Espírito do Senhor Deus está sobre mim. Atanásio de Alexandria vê nesta profecia uma predição de Cristo.', 'Atanásio de Alexandria', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('53b83ca5-da6a-4320-9775-f1fc3789c3d3', 'jr', 1, 1, NULL, 'Patrística', 'Antes que te formasse no ventre. Basílio Magno comenta que Deus conhece seus profetas.', 'Basílio Magno', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('1c6f294c-b6ca-4be2-89f8-e2186a792f89', 'jr', 23, 1, NULL, 'Patrística', 'Eis que vêm dias. Gregório de Nazianzo comenta sobre a restauração de Israel.', 'Gregório de Nazianzo', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('2c128531-8656-4c16-b75a-d7a15c4660f6', 'jr', 31, 1, NULL, 'Patrística', 'Eis que vêm dias. Gregório de Nissa comenta sobre a nova aliança em Cristo.', 'Gregório de Nissa', 'commentary', '#6B21A8', NOW());

