INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('c4c75ac6-e884-45db-863b-48f42c216546', 'dn', 7, 1, NULL, 'Patrística', 'Daniel viu uma visão. Clemente de Roma comenta sobre as quatro bestas.', 'Clemente de Roma', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('f84c9a0d-c723-4581-86a1-4103c9ca0838', 'dn', 9, 1, NULL, 'Patrística', 'Setenta semanas estão determinadas. Inácio de Antioquia comenta sobre a profecia messiânica.', 'Inácio de Antioquia', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('6a0310dc-9e69-4a3d-b0bd-11611cbae41d', 'dn', 12, 1, NULL, 'Patrística', 'Naquele tempo se levantará Miguel. Policarpo comenta sobre a ressurreição dos mortos.', 'Policarpo de Esmirna', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('c09f820f-0b05-4ea1-b2a7-d21d6b13762c', 'os', 2, 1, NULL, 'Patrística', 'Desposar-te-ei comigo para sempre. Justino Mártir comenta sobre a restauração de Israel.', 'Justino Mártir', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('7ae3b977-1862-4511-ab30-5b21f6435306', 'os', 6, 1, NULL, 'Patrística', 'Vinde, tornemos para o Senhor. Irineu de Lyon comenta sobre o arrependimento.', 'Irineu de Lyon', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('1ab4d11e-1b17-4878-b100-bcfddbc95627', 'jl', 2, 1, NULL, 'Patrística', 'Derramarei o meu Espírito. Tertuliano comenta sobre o Pentecostes.', 'Tertuliano', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('22b87571-153d-4e82-939f-c9fa23fa34df', 'jl', 3, 1, NULL, 'Patrística', 'Naqueles dias e naquele tempo. Orígenes comenta sobre o julgamento final.', 'Orígenes', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('13fd7195-cef8-4e12-8631-3675e4fbb00e', 'am', 5, 1, NULL, 'Patrística', 'Buscai o bem e não o mal. Atanásio de Alexandria comenta sobre a justiça social.', 'Atanásio de Alexandria', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('56e28766-64ab-4f58-890a-fbd7ae3b588b', 'am', 9, 1, NULL, 'Patrística', 'Eis que os olhos do Senhor Deus. Basílio Magno comenta sobre a soberania de Deus.', 'Basílio Magno', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('155e905d-d616-4f5c-96bf-6cf73adbc7c4', 'mq', 5, 1, NULL, 'Patrística', 'De ti sairá aquele que há de reinar. Gregório de Nazianzo comenta sobre a profecia messiânica.', 'Gregório de Nazianzo', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('ceab7e3c-6d99-418b-b43d-e4ccb6661c61', 'na', 1, 1, NULL, 'Patrística', 'Profecia sobre Nínive. Gregório de Nissa comenta sobre o julgamento de Deus.', 'Gregório de Nissa', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('777fa82d-584d-4e05-adeb-2cb7d89c3a1c', 'hc', 3, 1, NULL, 'Patrística', 'Ainda que a figueira não floresça. João Crisóstomo comenta sobre a fé em tempos de crise.', 'João Crisóstomo', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('493d0f92-ab03-4323-8ddf-1b985ac0c9aa', 'zc', 9, 1, NULL, 'Patrística', 'Alegra-te muito, filha de Sião. Jerônimo comenta sobre a vinda do Messias.', 'Jerônimo', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('3bb6e9dd-472a-4974-895c-63f76613dbcc', 'zc', 12, 1, NULL, 'Patrística', 'Derramarei sobre a casa de Davi. Clemente de Roma comenta sobre o Espírito Santo.', 'Clemente de Roma', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('3a7b852e-53d1-41c1-b0cd-52c8c6d8f8bf', 'ml', 3, 1, NULL, 'Patrística', 'Eis que envio o meu mensageiro. Inácio de Antioquia comenta sobre João Batista.', 'Inácio de Antioquia', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('c6e89bb2-3062-43da-a610-010ee935d871', 'ml', 4, 1, NULL, 'Patrística', 'Mas para vós que temeis o meu nome. Policarpo comenta sobre a restauração final.', 'Policarpo de Esmirna', 'commentary', '#6B21A8', NOW());

